```
const drawWheel = (ctx: CanvasRenderingContext2D, x: number, y: number, radius: number, color: string) => {
    ctx.save();
    ctx.translate(x, y);

    // Rim
    ctx.fillStyle = COLORS.carRim;
    ctx.beginPath();
    ctx.arc(0, 0, radius * 0.9, 0, Math.PI * 2);
    ctx.fill();

    // Tire
    ctx.fillStyle = '#000000'; // Black color
    ctx.beginPath();
    ctx.arc(0, 0, radius, 0, Math.PI * 2);
    ctx.fill();

    // Rim
    ctx.fillStyle = COLORS.carRim; // Using constant from file or prop? The file has COLORS imported.
    ctx.beginPath();
    ctx.arc(0, 0, radius * 0.6, 0, Math.PI*2);
    ctx.fill();

    // Spokes
    ctx.strokeStyle = '#171717';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(-radius*0.6, 0); ctx.lineTo(radius*0.6, 0);
    ctx.moveTo(0, -radius*0.6); ctx.lineTo(0, radius*0.6);
    ctx.stroke();

    // Color Detail
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(0, 0, radius * 0.2, 0, Math.PI*2);
    ctx.fill();

    ctx.restore();
};

const drawCarDetails = (ctx: CanvasRenderingContext2D, car: CarModel, cw: number, ch: number, isGameOver: boolean) => {
    // Windows
    ctx.fillStyle = '#38bdf8'; // Sky blue tint
    ctx.globalAlpha = 0.6;
    if (car.shape === 'coupe' || !car.shape) {
        ctx.beginPath();
        ctx.moveTo(cw*0.1, -ch*0.8);
        ctx.lineTo(cw*0.4, -ch*0.8);
        ctx.lineTo(cw*0.5, -ch*0.2);
        ctx.lineTo(cw*0.1, -ch*0.2);
        ctx.closePath();
        ctx.fill();
    }
}
```


